  "verses": [
    {
      "n": 25,
      "column": "left",
      "text": "Ta nogabje Dahwids un\ntee Israëta Wezzajee/ un tee Ah-\nwersti/ ka tee ta KUNGA Der-\nribas Schkirstu no Obed-Eedo-\nma Namina ar Breeku augfcham\nwestu."
    },
    {
      "n": 26,
      "column": "left",
      "text": "Un kad Deewa teem Le-\nwiteem palihdfeja/ kas ta KUN-\nGA Derribas Schkirstu neffe/\ntad uppureja tee feptinus Wehr-\nschus un feptinus Annus."
    },
    {
      "n": 27,
      "column": "left",
      "text": "Un Dahwids bji apgehr-\nbees ar tinnu Swahrkeem/ un ta-\npatt wiſſi Lewiti/ kas to Schkir-\nstu neffe/ un tee Dseedatajt/ un\nKanantjus to Dseedataju ang-\nftajs Usluhkotajs/ ir Dahwidam\nbija weens tinnu Eewods Mug-\ngura."
    },
    {
      "n": 28,
      "column": "left",
      "text": "Ta nesse wiſſ Israëls ta\nKUNGA Derribas Schkirstu\naugfcham ar Gawileschanu/ un\nBasinn Puhschanu / un ar\nTrummetehtm/ un ar Pulksteni-\nscheem/ un spebleja ar Sohma-\nStabulehm/ un Kohklehm."
    },
    {
      "n": 29,
      "column": "left",
      "text": "Un kad ta KUNGA Der-\nribas Schkirsts lithds Dahwida\nPillim nahze/ tad ftattijahs Mi-\nkale Saula Meita zaur Lohgu\nahra / un redseja to Kehnizu\nDahwidu Detjam un spehlejam/\nun apfinehje to fawa Sirdi.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Ad tee nit to Deetwu\nSchkirstu ativede/ tad\nwiſſe tee winnu paſcha\nTelti/ ko Dahwids tam bij us-\nzehlis/ un tee uppureja Dedsa-\nmo-Uppurus/ un Pateikfchanas-\nUppurus Deewa Preekfcha."
    },
    {
      "n": 2,
      "column": "right",
      "text": "Un kad Dahwids tohs De-\ndsamo-Uppurus un Pateikfcha-\nnas-Uppurus bij pabeidſis/ tad\nfwehtija wiſſch tohs Laudis\neekſch ta KUNGA Wahrda."
    },
    {
      "n": 3,
      "column": "right",
      "text": "Un wiſſch isdallija ifkat-\nram no Israëta/ tik labbi Wihr-\nram ka Seewai/ weenu Maiseß\nKlaipu/un Galtas Gabbalu/un\nweenu Wihrna Stohpu."
    },
    {
      "n": 4,
      "column": "right",
      "text": "Un wiſſch liſſe preekſch ta\nKUNGA Schkirstu zittus no\nteem Lewiteein par Sullaineem/\nka tee peeminnetu/ teiktu un fla-\nwetu to KUNgu Israëta Deewu."
    },
    {
      "n": 5,
      "column": "right",
      "text": "Affaws bija par Wirfneku/\nun wiſſa ohtrs Sakarijus/ Jei-\nels/ Semiramots/ Jeiels un\nMatitijus/ un Elijabs/ un Be-\nnajus/ un Obed-Eedoms/ un Jei-\nels ar (spehlejameem) Rihkeim/\nSohma-Stabulehm / un ar\nKohklehm/ un Affaws tikahs ar\nPulkstenischeem dfirdetees."
    },
    {
      "n": 6,
      "column": "right",
      "text": "Un Benajus un Jeastëls\ntee Preesteri/ puhte weenunehr\nar Trummetehtm preektch Dee-\nwa Derribas Schkirsta."
    },
    {
      "n": 7,
      "column": "right",
      "text": "Tai Deena dewe Dah-\nwids pirnu Reisi fcho Dseedmu\nto KUNGU flaweht/ zaur Alfa-\nwu un wiſſa Brahteen."
    },
    {
      "n": 8,
      "column": "right",
      "text": "Teizeet to KUNGII/ pee-\nfanzceet"
    }
  ],
  "confidence": "high",
  "notes": ""
}
